extern int vx_dev_init(callbacks_t* callbacks) {
  if (nullptr == callbacks)
    return -1;

  callbacks->dev_open = [](vx_device_h* hdevice)->int {
    if (nullptr == hdevice)
      return  -1;
    auto device = new vx_device();
    if (device == nullptr)
      return -1;
    CHECK_ERR(device->init(), {
      delete device;
      return err;
    });
    DBGPRINT("DEV_OPEN: hdevice=%p\n", (void*)device);
    *hdevice = device;
    return 0;
  };

